} catch (e) {
    logger.error(" Error fetching FHIR API URL: " + e);
    setErrorResponse(500, "Failed to load FHIR API URL");
    throw e;
}


/********************************************
    8️⃣ FETCH HUB UI URL (Plain text)
********************************************/
