com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');

/**
 * Util function to generate JSON string
 */
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
 * Util function to set error response
 */
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode));
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponse(statusCode, errorMessage));
}

/* =====================================
   1️⃣ ROOT ENDPOINT
===================================== */
if (contextPath === '') {

   if (httpMethod === 'GET') {

    responseMap.put('responseStatusCode', 200);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify({
        status: 200,
        message: "OK"
    }));

   return false;
}

    // Method not allowed for /
    return methodNotAllowed();
}

/* =====================================
   2️⃣ HEALTHCHECK

===================================== */
if (contextPath === '/healthcheck') {

    if (httpMethod === 'GET') {
         responseMap.put('responseStatusCode', 200);
	    responseMap.put('responseContentType', 'application/json');
	    responseMap.put('responseBody', JSON.stringify({
	        status: 200,
	        message: "OK"
	    }));

	   return false;
    }

    return methodNotAllowed();
}

/* =====================================
   3️ BUNDLE
===================================== */
if (contextPath === '/Bundle/$validate' || contextPath === '/Bundle/$validate/') {

    if (httpMethod === 'POST' || httpMethod === 'OPTIONS') {
        return true;
    }

    return methodNotAllowed();
}

/* =====================================
   ❌ INVALID PATH → 404
===================================== */
return notFound();




/* =====================================
   Helper Functions
===================================== */

function methodNotAllowed() {

    var errorResponse = "Method Not Allowed.";

    responseMap.put('responseStatusCode', 405);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(405, errorResponse);

    throw "Invalid method";
}

function notFound() {

    var errorResponse = "Not Found: Invalid endpoint.";

    responseMap.put('responseStatusCode', 404);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(404, errorResponse);

    throw "Invalid endpoint";
}

channel.preprocessingScript:
///////////////////////////////////////////////////////////////////////////
// Access the required header values using getHeader method

var requestedPath = sourceMap.get('contextPath');

// Read both headers
var overridePath = $('headers').getHeader('X-TechBD-Override-Request-URI');
var requestUri = $('headers').getHeader('X-TechBD-Request-URI');

// Use whichever is present and non-empty (first check override, otherwise requestUri)
var effectivePath = (overridePath && overridePath.trim() !== '') 
    ? overridePath.trim() 
    : (requestUri && requestUri.trim() !== '') 
        ? requestUri.trim() 
        : null;

// If we found a usable override path, apply it
if (effectivePath !== null) {
    requestedPath = effectivePath;
}

channelMap.put("requestedPath", requestedPath);


if (requestedPath == "/") {
	return;
}


// ---- REQUEST BODY VALIDATION ----

if (message == null || String(message).trim() === "") {
    var errorMessage = "Validation Error: Required request body is missing";
    logger.error(errorMessage);
    setErrorResponsePre(400, errorMessage);
    throw errorMessage;
}

channelMap.put('channelName',channelName);

var incomingInteractionId = $('headers').getHeader('X-TechBD-Interaction-ID');
var incomingCorrelationId = $('headers').getHeader('X-Correlation-ID');

var interactionId;

if (incomingInteractionId != null && incomingInteractionId.trim() !== '') {
    interactionId = incomingInteractionId;
} else if (incomingCorrelationId != null && incomingCorrelationId.trim() !== '') {
    interactionId = incomingCorrelationId;
} else {
    interactionId = generateUuid();
}

channelMap.put('interactionId', interactionId);

var source = "FHIR";
var incomingSource = sourceMap.get('source');

if (incomingSource != null && incomingSource.trim() !== '') {
    source = incomingSource;
}

channelMap.put('source', source);
logger.info("Source: " + source);





var tenantId = $('headers').getHeader('X-TechBD-Tenant-ID');
logger.info("[CHANNEL: 1115 TECHBD " + channelName + " ][INTERACTION ID: " +interactionId +" ]: tenantid: " + tenantId); // Mirth helper that accepts channelMap
channelMap.put('tenantId', tenantId);



var userAgent = $('headers').getHeader('User-Agent');
channelMap.put('userAgent', userAgent);



var elaboration = "";
var incomingElaboration = $('headers').getHeader('X-TechBD-Elaboration');

// If header has valid value, use it; otherwise keep default (empty string or any fallback)
if (incomingElaboration != null && incomingElaboration.trim() !== '') {
    elaboration = incomingElaboration.trim();
}

channelMap.put("elaboration", elaboration);

var healthCheck = "";
var incomingHealthCheck = $('headers').getHeader('X-TechBD-HealthCheck');

if (incomingHealthCheck != null && incomingHealthCheck.trim() !== '') {
    healthCheck = incomingHealthCheck.trim();
}

channelMap.put("healthCheck", healthCheck);



var igVersion = "";
var incomingIgVersion = $('headers').getHeader('X-SHIN-NY-IG-Version');

if (incomingIgVersion != null && incomingIgVersion.trim() !== '') {
    igVersion = incomingIgVersion;
}

channelMap.put('igVersion', igVersion);






var validationSeverityLevel = "error";
var incomingSeverity = $('headers').getHeader('X-TechBD-Validation-Severity-Level');

// If header has valid value, use it; otherwise keep default
if (incomingSeverity != null && incomingSeverity.trim() !== '') {
    validationSeverityLevel = incomingSeverity;
}

channelMap.put("validationSeverityLevel",validationSeverityLevel);

// Check if the header is null or empty
if (tenantId == null || String(tenantId).trim() === "") {
    // Log the error for debugging
    var errorMessage = 'Bad Request: Missing required header X-TechBD-Tenant-ID';
    logger.error(errorMessage);
    setErrorResponsePre(400, errorMessage); // Set the HTTP response status to 400 (Bad Request)
    throw errorMessage; // Stop further processing by throwing an exception
}

function setErrorResponsePre(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode)); // Set HTTP status
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponsePre(statusCode, errorMessage));
}
function createJsonResponsePre(status, message) {
    return JSON.stringify({ status: status, message: message });
}

return message;

channel.postprocessingScript:
var chlName = channelMap.get('channelName');
var interactionId = channelMap.get('interactionId');

var requestedPath = channelMap.get('requestedPath');
if (requestedPath == "/") {
	return;
}


logger.info("[CHANNEL: 1115 TECHBD " + chlName + "][INTERACTION ID: " +interactionId +" ]: Postprocessor STARTS.");
var endpoint = channelMap.get("endpoint");
if(endpoint == 'validate') {
	// Get the response from the HTTP Writer destination
	var destinationName = "dest_bundle";
	var destinationResponse = responseMap.get(destinationName);

	// Check if the response exists
	if (destinationResponse) {
	    var responseStatus = destinationResponse.getStatus();  // HTTP status code
	    var responseData = destinationResponse.getMessage();   // Response message body
		responseMap.put('finalResponse', responseData);
		
	    // Log the response details
	    logger.info("[CHANNEL: 1115 TECHBD " + chlName + "][INTERACTION ID: " +interactionId +" ]:Response from " + destinationName + ":" + ":Status Code: " + responseStatus + " :Response Data: " + responseData);
	} else {
	    logger.info("[CHANNEL: 1115 TECHBD " + chlName + "][INTERACTION ID: " +interactionId +" ]:No response found for destination: " + destinationName);
	}
}
logger.info("[CHANNEL: 1115 TECHBD " + chlName + "][INTERACTION ID: " +interactionId +" ]: Postprocessor ENDS.");

return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data

/**
* Util function to generate json string wit hstatus and message
*/

function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
* Util function to set error response.
*/
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode)); // Set HTTP status
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponse(statusCode, errorMessage));
}




function toJsonb(value) {
    var jsonbObj = new PGobject();
    jsonbObj.setType("jsonb");

	if (typeof value === "object") {
        value = JSON.stringify(value);
    }
    
    jsonbObj.setValue(value);
    logger.info("jsonbObj: " + jsonbObj);
    return jsonbObj;
}

// Function to extract a query param from the URI
function getQueryParam(uriString, paramName) {
    if (!uriString) return null;
    var regex = new RegExp('[?&]' + paramName + '=([^&]*)', 'i');
    var match = uriString.match(regex);
    return (match && match[1]) ? decodeURIComponent(match[1]) : null;
}
globalMap.put('getQueryParam', getQueryParam);


return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

properties.code:
/**
	Util function to set error response.

	@param {Any} statusCode - 
	@param {Any} errorMessage - 
	@param {Any} map - 
	@return {Any} 
*/
function setErrorResponse(statusCode, errorMessage, map) {
    var targetMap = map || responseMap;

    var json = createJsonResponse(statusCode, errorMessage);
    targetMap.put('status', String(statusCode));
    targetMap.put('responseStatusCode', statusCode);
    targetMap.put('fhirResponse', json);
    targetMap.put('finalResponse', json);
}
/**
 Util function to generate json string wit hstatus and message
*/
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}
